rss.channel:
{% if order == 'deleted' %}
  {{ config['MYSERVER_NAME_SHORT'] }}:Channels:Deleted
  https://{{ config['MYSERVER_NAME'] }}/channel/deleted

  {{ channelcount | viewdisplay }} Deleted Channels

      https://{{ config['MYSERVER_NAME'] }}/alt_favicon_140_140.jpg
      {{ config['MYSERVER_NAME_SHORT'] }}:Channels
      https://{{ config['MYSERVER_NAME'] }}

{% else %}
  {{ config['MYSERVER_NAME_SHORT'] }}:Channels
  https://{{ config['MYSERVER_NAME'] }}/channel

  {{ channelcount | viewdisplay }} Monitored/Archived Channels

      https://{{ config['MYSERVER_NAME'] }}/alt_favicon_140_140.jpg
      {{ config['MYSERVER_NAME_SHORT'] }}:Channels
      https://{{ config['MYSERVER_NAME'] }}

{% endif %}
    {% for channel in channels %}


        {{ channel['title']  }}
        https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['extractor_data']) }}
        https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['extractor_data']) }}


          <a href="https://{{ config['MYSERVER_NAME'] }}{{ url_for('channel.item', ytc_id=channel['extractor_data']) }}">
            <img
             src="{{ channel['thumbnail_ytapi'] | reverse | replace('88','671', 1) | reverse  }}" >
            </style>
          </a>
          <p>
          <b>Total Videos: {{ channel['total'] }}</b><br>
          <b>Limited/Removed Videos: {{ channel['limited'] }}</b><br>
          <b>Views:</b> {{ channel['view_count'] }}<br>
          <b>Subscribers:</b> {{ channel['channel_follower_count'] }}<br>
          <b>Created Date:</b> {{ channel['published_at'].strftime('%Y-%m-%d') if channel['published_at'] else '' }}<br>
        {% if channel['deleted'] %}
          <b>Deleted Date:</b>{{ channel['deleted_date'].strftime('%Y-%m-%d') if channel['deleted_date'] else '' }}<br>
        {% endif %}
        {% if channel['added_date'] %}
           <b>Added to altCensored Date:</b> {{ channel['added_date'].strftime('%Y-%m-%d') }}<br>
        {% endif %}
          <b>YouTube Channel ID:</b> {{ channel['extractor_data'] }}<br>
          <b>YouTube Channel URL:</b> https://www.youtube.com/channel/{{ channel['extractor_data'] }}
          <p>
        {% if channel['description'] %}
          {{ channel['description'] | linkify | safe | nl2br | truncate (1200) }}
        {% endif %}


        {{ channel['total'] }}
        {{ channel['limited'] }}
        {{ channel['view_count'] }}
        {{ channel['channel_follower_count'] }}
        {{ channel['published_at'] }}
        {{ channel['deleted_date'] }}
        {{ channel['added_date'] }}
        {{ channel['extractor_data'] }}
        https://www.youtube.com/channel/{{ channel['extractor_data'] }}
        https://socialblade.com/youtube/channel/{{ channel['extractor_data'] }}
        {% if channel['description'] %}
            {{ channel['description'] | linkify | safe | nl2br | truncate (35) }}  
        {% else %}
            {{ channel['description'] }}  
        {% endif %}
        {% if channel['deleted'] %}
        {{ channel['deleted_date'].strftime('%a, %d %b %Y %T') if channel['deleted_date'] else '' }} EST
        {% else %}
        {{ channel['added_date'].strftime('%a, %d %b %Y %T') if channel['added_date'] else '' }} EST
        {% endif %}

    {% endfor %}
